                "System", "Thread", "exec", "load", "loadLibrary",
                // OGNL context / member access manipulation
                "_memberAccess", "memberAccess", "context", "#", "$",
                // method calls / indexing / maps / projections / selections / assignments
                "(", ")", "[", "]", "{", "}", "=", "?", ":", ",", ";", "+", "-", "*", "/", "%", "!"
